create type public.subscription_status as enum('trialing','active','past_due','grace_period','suspended','cancelled','expired');
create table public.subscription_plans(id uuid primary key default gen_random_uuid(),code text not null unique,name text not null,status entity_status not null default 'active',trial_days integer not null default 14,limits jsonb not null default '{}',features jsonb not null default '{}',created_at timestamptz not null default now());
create table public.organization_subscriptions(id uuid primary key default gen_random_uuid(),organization_id uuid not null unique references organizations,plan_id uuid not null references subscription_plans,status subscription_status not null default 'trialing',trial_started_at timestamptz not null default now(),trial_ends_at timestamptz not null default(now()+interval '14 days'),created_at timestamptz not null default now());
create table public.subscription_usage(id uuid primary key default gen_random_uuid(),organization_id uuid not null references organizations,metric text not null,period_start date not null,period_end date not null,used integer not null default 0,unique(organization_id,metric,period_start));
alter table subscription_plans enable row level security;alter table organization_subscriptions enable row level security;alter table subscription_usage enable row level security;
create policy plans_read on subscription_plans for select to authenticated using(status='active');create policy own_subscription_read on organization_subscriptions for select to authenticated using(organization_id=private.current_organization_id());create policy own_usage_read on subscription_usage for select to authenticated using(organization_id=private.current_organization_id());
insert into subscription_plans(code,name,limits,features) values('trial','Prueba 14 días','{"branches":1,"users":5,"applications_monthly":30}','{"credit":true,"inventory":true,"payments":true}'),('starter','Inicial','{"branches":1,"users":8,"applications_monthly":100}','{"credit":true,"inventory":true,"payments":true}'),('growth','Crecimiento','{"branches":3,"users":25,"applications_monthly":500}','{"credit":true,"inventory":true,"payments":true,"collections":true}') on conflict(code) do nothing;
insert into organization_subscriptions(organization_id,plan_id) select o.id,p.id from organizations o cross join subscription_plans p where p.code='trial' on conflict(organization_id) do nothing;
insert into permissions(code,description) values('organization.owner','Control total de la organización') on conflict(code) do nothing;
insert into roles(organization_id,name,description,is_system) select id,'organization_owner','Dueño de la organización',true from organizations on conflict(organization_id,name) do nothing;
insert into role_permissions(role_id,permission_id) select r.id,p.id from roles r cross join permissions p where r.name='organization_owner' on conflict do nothing;
